import React, { useState } from "react";
import DepositScreen from "./DepositScreen";
import WithdrawScreen from "./WithdrawScreen";
import TransactionHistoryScreen from "./TransactionHistoryScreen";
import TransactionReceiptScreen from "./TransactionReceiptScreen";

export default function HomeScreen() {
  const [view, setView] = useState("home"); // home | deposit | withdraw | history | receipt
  const [balance, setBalance] = useState(5000);
  const [transactions, setTransactions] = useState([]);
  const [selectedTransaction, setSelectedTransaction] = useState(null);

  // Deposit
  const handleDeposit = (amount) => {
    const tx = {
      id: Date.now(),
      type: "Deposit",
      amount,
      date: new Date().toLocaleString(),
      reference: `DEP${Math.floor(Math.random() * 1000000)}`,
    };
    setTransactions([tx, ...transactions]);
    setBalance(balance + amount);
    setSelectedTransaction(tx);
    setView("receipt");
  };

  // Withdraw
  const handleWithdraw = (amount) => {
    const tx = {
      id: Date.now(),
      type: "Withdrawal",
      amount,
      date: new Date().toLocaleString(),
      reference: `WTH${Math.floor(Math.random() * 1000000)}`,
    };
    setTransactions([tx, ...transactions]);
    setBalance(balance - amount);
    setSelectedTransaction(tx);
    setView("receipt");
  };

  // Select transaction from history
  const handleSelectTransaction = (tx) => {
    setSelectedTransaction(tx);
    setView("receipt");
  };

  // Render
  switch (view) {
    case "deposit":
      return (
        <DepositScreen
          onDeposit={handleDeposit}
          onBack={() => setView("home")}
        />
      );
    case "withdraw":
      return (
        <WithdrawScreen
          balance={balance}
          onWithdraw={handleWithdraw}
          onBack={() => setView("home")}
        />
      );
    case "history":
      return (
        <TransactionHistoryScreen
          transactions={transactions}
          onSelectTransaction={handleSelectTransaction}
          onBack={() => setView("home")}
        />
      );
    case "receipt":
      return (
        <TransactionReceiptScreen
          transaction={selectedTransaction}
          onBack={() => setView("home")}
        />
      );
    default:
      // Home view (simplified Gemini buttons)
      return (
        <div className="min-h-screen bg-[#f4f6fb] px-5 pt-6 pb-24 flex flex-col gap-6">
          <h1 className="text-xl font-semibold text-gray-900">
            Welcome
          </h1>
          <p className="text-gray-500">
            Balance: ₦{balance.toLocaleString()}
          </p>

          <button
            onClick={() => setView("deposit")}
            className="w-full bg-emerald-600 text-white py-4 rounded-xl font-semibold active:scale-[0.98] transition"
          >
            Deposit
          </button>

          <button
            onClick={() => setView("withdraw")}
            className="w-full bg-white border border-gray-300 py-4 rounded-xl font-semibold text-gray-900 active:scale-[0.98] transition"
          >
            Withdraw
          </button>

          <button
            onClick={() => setView("history")}
            className="w-full bg-white border border-gray-300 py-4 rounded-xl font-semibold text-gray-900 active:scale-[0.98] transition"
          >
            Transaction History
          </button>
        </div>
      );
  }
}
